package bead

import "io"

// RawBackend is the low-level storage contract — read/write the entire bead
// corpus and serialize concurrent rewrites. JSONLBackend and ExternalBackend
// implement it. Higher-level operations (CRUD, claim, ready/blocked, dep ops,
// events, archive, JSONL interchange) live on the Backend interface below and
// are composed on top of a RawBackend by Store.
type RawBackend interface {
	Init() error
	ReadAll() ([]Bead, error)
	WriteAll(beads []Bead) error
	WithLock(fn func() error) error
}

// Backend is the high-level bead-tracker contract that callers in
// cli/cmd/bead_*.go and the agent loop will eventually program against. It
// covers everything the bead description for ddx-bbdd7564 calls out: CRUD,
// claim, list/ready/blocked, dep ops, events append, archive split, and
// JSONL export/import.
//
// *Store satisfies this interface; the JSONL implementation lives in store.go
// and delegates per-write serialization to the configured RawBackend
// (JSONLBackend by default, ExternalBackend when DDX_BEAD_BACKEND or the
// .ddx/config.yaml beads.backend field selects bd/br).
//
// chaos_test.go and other conformance suites should program against this
// interface so additional backends can be exercised by the same tests.
type Backend interface {
	// Foundational
	Init() error
	ReadAll() ([]Bead, error)

	// CRUD
	Create(b *Bead) error
	Get(id string) (*Bead, error)
	Update(id string, mutate func(*Bead)) error
	Close(id string) error

	// Claim
	Claim(id, assignee string) error
	ClaimWithOptions(id, assignee, session, worktree string) error
	Unclaim(id string) error

	// Query
	List(status, label string, where map[string]string) ([]Bead, error)
	Ready() ([]Bead, error)
	Blocked() ([]Bead, error)

	// Dep ops
	DepAdd(id, depID string) error
	DepRemove(id, depID string) error
	DepTree(rootID string) (string, error)

	// Events
	AppendEvent(id string, event BeadEvent) error
	Events(id string) ([]BeadEvent, error)

	// Archive split
	Archive(policy ArchivePolicy) ([]string, error)
	Migrate() (MigrateStats, error)

	// JSONL interchange
	Import(source, filePath string) (int, error)
	ExportTo(w io.Writer) error
}

// BackendType constants
const (
	BackendJSONL = "jsonl"
	BackendBD    = "bd"
	BackendBR    = "br"
)

const DefaultCollection = "beads"

package bead

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"sync"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// newAxonStore returns a *Store wired to a fresh AxonBackend rooted at a
// temp dir. Mirrors newTestStore so the existing high-level Backend method
// surface (Create/Get/Update/Claim/Close/...) gets exercised against the
// axon-shaped storage layout instead of the JSONL default.
func newAxonStore(t *testing.T) *Store {
	s, _ := newAxonStoreWithTransport(t)
	return s
}

func newAxonStoreWithTransport(t *testing.T) (*Store, *fakeAxonGraphQLTransport) {
	t.Helper()
	dir := filepath.Join(t.TempDir(), ".ddx")
	transport := newFakeAxonGraphQLTransport()
	s := NewStore(dir)
	s.backend = NewAxonBackend(dir, s.LockWait,
		WithAxonGraphQLTransport(transport),
		WithAxonGraphQLClient(transport),
	)
	require.NoError(t, s.Init())
	return s, transport
}

type fakeAxonGraphQLTransport struct {
	mu     sync.Mutex
	beads  []axonEntityEnvelope
	events []axonEventEnvelope
}

func newFakeAxonGraphQLTransport() *fakeAxonGraphQLTransport {
	return &fakeAxonGraphQLTransport{}
}

func (t *fakeAxonGraphQLTransport) Query(_ context.Context, query string, variables map[string]any, response any) error {
	t.mu.Lock()
	defer t.mu.Unlock()
	switch query {
	case axonReadCorpusQuery:
		if response == nil {
			return nil
		}
		resp, ok := response.(*axonCorpusResponse)
		if !ok {
			return fmt.Errorf("unexpected response type %T", response)
		}
		resp.Beads = append(resp.Beads[:0], t.beads...)
		resp.Events = append(resp.Events[:0], t.events...)
		return nil
	case axonWriteCorpusMutation:
		var beads []axonEntityEnvelope
		var events []axonEventEnvelope
		if raw, ok := variables["beads"]; ok {
			if err := decodeJSONValue(raw, &beads); err != nil {
				return err
			}
		}
		if raw, ok := variables["events"]; ok {
			if err := decodeJSONValue(raw, &events); err != nil {
				return err
			}
		}
		t.beads = append(t.beads[:0], beads...)
		t.events = append(t.events[:0], events...)
		if response != nil {
			if resp, ok := response.(*axonWriteCorpusResponse); ok {
				resp.SaveCorpus.OK = true
			}
		}
		return nil
	default:
		return fmt.Errorf("unexpected query %q", query)
	}
}

func decodeJSONValue(src any, dst any) error {
	raw, err := json.Marshal(src)
	if err != nil {
		return err
	}
	return json.Unmarshal(raw, dst)
}

func (t *fakeAxonGraphQLTransport) snapshot() ([]axonEntityEnvelope, []axonEventEnvelope) {
	t.mu.Lock()
	defer t.mu.Unlock()
	beads := append([]axonEntityEnvelope(nil), t.beads...)
	events := append([]axonEventEnvelope(nil), t.events...)
	return beads, events
}

type stubAxonGraphQLTransport struct{}

func (stubAxonGraphQLTransport) Query(context.Context, string, map[string]any, any) error {
	return nil
}

func TestAxonBackend_GraphQLClientBoundary(t *testing.T) {
	t.Parallel()

	dir := filepath.Join(t.TempDir(), ".ddx")
	transport := stubAxonGraphQLTransport{}
	client := struct{ Name string }{Name: "stub"}

	ax := NewAxonBackend(dir, 3*time.Second,
		WithAxonGraphQLTransport(transport),
		WithAxonGraphQLClient(client),
	)

	assert.IsType(t, transport, ax.GraphQLTransport)
	assert.Equal(t, transport, ax.GraphQLTransport)
	require.Equal(t, client, ax.GraphQLClient)
	assert.Equal(t, filepath.Join(dir, AxonDirName), ax.Dir)
	assert.Equal(t, filepath.Join(dir, AxonDirName, AxonBeadsCollection+".jsonl"), ax.BeadsFile)
	assert.Equal(t, filepath.Join(dir, AxonDirName, AxonEventsCollection+".jsonl"), ax.EventsFile)

	plain := NewAxonBackend(dir, 3*time.Second)
	assert.Nil(t, plain.GraphQLTransport)
	assert.Nil(t, plain.GraphQLClient)
}

func TestAxonBackend_InitCreatesCollections(t *testing.T) {
	t.Parallel()
	s := newAxonStore(t)
	ax, ok := s.backend.(*AxonBackend)
	require.True(t, ok)

	for _, path := range []string{ax.BeadsFile, ax.EventsFile} {
		_, err := os.Stat(path)
		assert.NoError(t, err, "axon collection file %s should exist after Init", path)
	}
}

func TestAxonBackend_GraphQLMapping_BeadsAndEvents(t *testing.T) {
	t.Parallel()

	local := Bead{
		ID:          "ddx-00000001",
		Title:       "mapped",
		Status:      StatusOpen,
		Priority:    2,
		IssueType:   DefaultType,
		Owner:       "owner",
		CreatedAt:   time.Unix(10, 0).UTC(),
		CreatedBy:   "creator",
		UpdatedAt:   time.Unix(20, 0).UTC(),
		Labels:      []string{"kind:feature"},
		Parent:      "ddx-00000002",
		Description: "local model",
		Acceptance:  "AC",
		Notes:       "notes",
		Dependencies: []Dependency{{
			IssueID:     "ddx-00000001",
